hooks.command:
python3 -c "
import sys, re, json
try:
    data = json.load(sys.stdin)
    f = data.get('tool_input', {}).get('file_path', '')
    if not f.endswith('.cs'): sys.exit(0)
    lines = open(f, encoding='utf-8').readlines()
    hits = [(i+1, line.rstrip()) for i, line in enumerate(lines) if re.search(r'[\u4e00-\u9fff]', line)]
    if hits:
        out = {'hookSpecificOutput': {'hookEventName': 'PostToolUse', 'additionalContext': '[한자경고] ' + f + ': ' + ', '.join(f'L{n}' for n,_ in hits)}}
        import json as j; print(j.dumps(out))
except: pass
"
